import React, { useState } from "react";
import { NavLink } from "react-router-dom";
import Nav from "./Nev";
import { useNavigate } from "react-router-dom";

function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleEmailChange = (event) => {
    setEmail(event.target.value);
  };

  const handlePasswordChange = (event) => {
    setPassword(event.target.value);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    setLoading(true);

    fetch("http://localhost/Petshop/login.php?email=" + email + "&password=" + password)
      .then((response) => response.json())
      .then((result) => {
        setLoading(false);

        // FIX: pehle check karo array empty toh nahi
        if (result != null && result.length > 0) {
          if (email == result[0].email && password == result[0].password) {
            alert("Login Successful! Welcome " + result[0].uname);
            localStorage.setItem("id", result[0].id);
            localStorage.setItem("uname", result[0].uname);
            localStorage.setItem("email", result[0].email);
            localStorage.setItem("islogin", true);
            navigate('/');
          } else {
            alert("Email ya Password galat hai!");
          }
        } else {
          alert("Koi account nahi mila! Pehle Signup karo.");
        }
      })
      .catch((error) => {
        setLoading(false);
        alert("Server se connect nahi ho pa raha. XAMPP chalu hai? Error: " + error.message);
      });
  };

  return (
    <div>
      <Nav></Nav>

      <link
        rel="stylesheet"
        href="https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/css/bootstrap.min.css"
      />

      <style dangerouslySetInnerHTML={{
        __html: `
          .login-form {
            width: 340px;
            margin: 50px auto;
            position: relative;
            top: 80px;
          }
          .login-form form {
            margin-bottom: 15px;
            background: #f7f7f7;
            box-shadow: 0px 2px 2px rgba(0, 0, 0, 0.3);
            padding: 30px;
            border-radius: 8px;
          }
          .login-form h2 {
            margin: 0 0 15px;
          }
          .form-control, .btn {
            min-height: 38px;
            border-radius: 2px;
          }
          .btn-login {
            font-size: 15px;
            font-weight: bold;
            background-color: #e44d26;
            color: white;
            border: none;
            width: 100%;
            padding: 10px;
            border-radius: 4px;
            cursor: pointer;
          }
          .btn-login:hover {
            background-color: #c0392b;
          }
          .btn-login:disabled {
            background-color: #aaa;
            cursor: not-allowed;
          }
        `
      }} />

      <div className="login-form">
        <form onSubmit={handleSubmit}>
          <h2 className="text-center">Log in</h2>

          <div className="form-group">
            <input
              type="text"
              className="form-control"
              placeholder="Email"
              required
              value={email}
              onChange={handleEmailChange}
            />
          </div>

          <div className="form-group">
            <input
              type="password"
              className="form-control"
              placeholder="Password"
              required
              value={password}
              onChange={handlePasswordChange}
            />
          </div>

          <div className="form-group">
            <button
              type="submit"
              className="btn-login"
              disabled={loading}
            >
              {loading ? "Login ho raha hai..." : "Log in"}
            </button>
          </div>

          <div className="clearfix">
            <label className="pull-left checkbox-inline">
              <input type="checkbox" /> Remember me
            </label>
          </div>
        </form>

        <p className="text-center">
          <NavLink to="/signup">Create an Account</NavLink>
        </p>
      </div>
    </div>
  );
}

export default Login;
